  function focusGraphNode(focusId) {
    if (!focusId || !state.network) return;
    try {
      state.network.focus(focusId, { scale: 1.2, animation: { duration: 350, easingFunction: "easeInOutQuad" } });
    } catch (_) {
    }
  }

